var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"후후, 꽤나 재미있는 장난을 치셨더군요?","JPN":"ふふ、随分と面白い意地悪をしてくれましたね。","ENG":"Fu fuu, you’ve pulled an interesting number on me.","TWN":"呵呵，你還真會開玩笑呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"감히 일생에 한 번뿐인 결혼식에서 본인 대신 이런 고철덩어리를 내보내실 줄이야.","JPN":"一生に一度きりの結婚式に本人の代わりにこのようなくず鉄を送るとはねえ。","ENG":"To think that you’d walk down the aisle in this piece of scrap-metal, instead of attending in person.","TWN":"一生一次的婚姻大事，竟然派一塊廢鐵來代表你出席。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"이런 치욕은 꽤나 오랜만이랍니다, 여보?","JPN":"こんな屈辱は久しぶりですわ、あなた。","ENG":"It’s been a while since I’ve been humiliated like this, Sweet Heart.","TWN":"我好久沒受到這種屈辱呢，老公？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"하지만 저를 속이신 만큼 그 대가는 확실히 치루어야겠죠?","JPN":"でも私を騙した分の代償はきっちり払うべきでしょうね。","ENG":"You’re going to pay for tricking me like that.","TWN":"你應該知道，開這種玩笑要付出相對的代價吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"후훗, 그럼 이렇게……!","JPN":"ウフフ、それではこう……！","ENG":"Haha, like this...!","TWN":"呵呵，那……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_ON","text":{"KOREA":"이건 어때요? 하앗……!","JPN":"これはどうですか？　はあっ……！","ENG":"How’s this? Hah...!","TWN":"這樣如何？哈……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_ON","text":{"KOREA":"어머나~ 이걸로도 부족하시다고요? 그렇다면……!","JPN":"まあ～これでも足りないのですか？　でしたら……！","ENG":"Oh... Is this not enough for you? Then...!","TWN":"哎呀～這樣還不夠嗎？那……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"어머, 뭔가요? 그 부러운 눈초리는?","JPN":"あら、何でしょう？　その羨ましそうな眼差しは。","ENG":"Oh? What’s that look on your face?","TWN":"喔，你那羨慕的眼光是怎麼回事？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"설마 제 발밑에 이 깡통에게 질투심이라도 품으신 건가요?","JPN":"まさか私の足の下にあるこの缶に嫉妬でもしているのですか？","ENG":"Are you jealous of this tin can beneath my feet?","TWN":"你該不會是忌妒我腳下的這個鐵桶吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"의외로 귀여운 면도 있으시군요, 여보.","JPN":"意外と可愛い一面もあるのですね、あなた。","ENG":"How cute of you, Sweet Heart.","TWN":"沒想到你也有這麼可愛的一面呢，老公。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"후후, 하지만 걱정마세요, 지금이라도 사죄하며 이 종이 쪼가리에 도장 한 번만 찍어주신다면…….","JPN":"ウフフ、でも心配しないでください。今からでも謝って、この紙切れに印を押してくれたら……","ENG":"Fu Fuu, don’t worry. It’s not too late to beg for my forgiveness and sign these papers...","TWN":"呵呵，別擔心，只要你現在跟我謝罪，並且在這張紙上蓋章……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"오늘 밤에는 특별한 벌을 드리도록 하죠.","JPN":"今夜は特別な罰を与えましょう。","ENG":"And then you’ll be rewarded with a special punishment tonight.","TWN":"那我今天晚上就給你來點特別的懲罰。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARAB_QLIPHOTH_WEDDING_NULL","text":{"KOREA":"제발 그만해 달라고 애원할 만큼…… 아주 아주 뜨거운 벌을. 후훗.","JPN":"やめてくれと哀願するくらい……とてもとても熱い罰をね。ウフフ。","ENG":"A punishment so intense... You’ll be begging me to stop.","TWN":"讓你求生不能，求死不得的……激烈懲罰，呵呵。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};